import React, { useState } from 'react';
import { Avatar, Stars, StatusBadge } from '../components/UI';

export default function AdminPage({ bookings, providers, onUpdateStatus }) {
  const [tab, setTab] = useState('bookings');

  const totalRevenue = bookings.filter(b => b.status === 'Completed').reduce((a, b) => a + b.price, 0);
  const pending   = bookings.filter(b => b.status === 'Pending').length;
  const accepted  = bookings.filter(b => b.status === 'Accepted').length;
  const completed = bookings.filter(b => b.status === 'Completed').length;

  const METRICS = [
    ['Total Revenue',    '$' + totalRevenue, '💰', 'var(--green)'],
    ['Active Bookings',  pending + accepted,  '📋', 'var(--blue)'],
    ['Providers',        providers.length,    '👥', 'var(--navy)'],
    ['Completed Jobs',   completed,           '✅', '#8b5cf6'],
  ];

  return (
    <div className="section">
      <div style={{ marginBottom: 28 }}>
        <h2 style={{ fontSize: 24, color: 'var(--navy)' }}>Admin Panel</h2>
        <p style={{ color: 'var(--gray-500)', marginTop: 4 }}>Platform overview and management</p>
      </div>

      {/* Metrics */}
      <div className="grid-4" style={{ marginBottom: 28 }}>
        {METRICS.map(([label, value, icon, accent]) => (
          <div key={label} style={{
            background: 'white', border: '1px solid var(--gray-200)',
            borderRadius: 14, padding: 20, borderTop: `4px solid ${accent}`,
          }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
              <div>
                <div style={{ fontSize: 13, color: 'var(--gray-500)', marginBottom: 6 }}>{label}</div>
                <div style={{ fontSize: 26, fontWeight: 700, color: 'var(--navy)', fontFamily: 'Sora' }}>{value}</div>
              </div>
              <div style={{ fontSize: 24 }}>{icon}</div>
            </div>
          </div>
        ))}
      </div>

      {/* Status breakdown */}
      <div className="card" style={{ marginBottom: 20 }}>
        <h3 style={{ fontSize: 16, color: 'var(--navy)', marginBottom: 16 }}>Booking Status Breakdown</h3>
        {[['Pending', pending, '#f59e0b'], ['Accepted', accepted, '#3b82f6'], ['Completed', completed, '#22c55e']].map(([label, count, color]) => (
          <div key={label} style={{ marginBottom: 12 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
              <span style={{ fontSize: 13, fontWeight: 500 }}>{label}</span>
              <span style={{ fontSize: 13, color: 'var(--gray-500)' }}>{count}</span>
            </div>
            <div className="progress-bar">
              <div className="progress-fill" style={{
                width: `${bookings.length ? (count / bookings.length * 100) : 0}%`,
                background: color,
              }} />
            </div>
          </div>
        ))}
      </div>

      {/* Tab selector */}
      <div className="tab-pills" style={{ marginBottom: 20 }}>
        {[['bookings','All Bookings'],['providers','All Providers']].map(([k, l]) => (
          <button key={k} className={`tab-pill ${tab === k ? 'active' : ''}`} onClick={() => setTab(k)}>{l}</button>
        ))}
      </div>

      {/* ---- Bookings Table ---- */}
      {tab === 'bookings' && (
        <div style={{ overflowX: 'auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
            <thead>
              <tr style={{ borderBottom: '2px solid var(--gray-200)' }}>
                {['ID','Service','Date','Zip','Provider','Status','Price','Action'].map(h => (
                  <th key={h} style={{
                    padding: '10px 12px', textAlign: 'left',
                    color: 'var(--gray-500)', fontWeight: 600, fontSize: 12,
                  }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {bookings.map(b => (
                <tr key={b.id} style={{ borderBottom: '1px solid var(--gray-100)' }}>
                  <td style={{ padding: '12px' }}>
                    <code style={{ fontSize: 11, background: 'var(--gray-100)', padding: '2px 6px', borderRadius: 4 }}>
                      {b.id}
                    </code>
                  </td>
                  <td style={{ padding: '12px', fontWeight: 500, color: 'var(--navy)' }}>{b.service}</td>
                  <td style={{ padding: '12px', color: 'var(--gray-600)' }}>{b.date}</td>
                  <td style={{ padding: '12px', color: 'var(--gray-600)' }}>{b.zip}</td>
                  <td style={{ padding: '12px', color: 'var(--gray-600)' }}>{b.providerName || '—'}</td>
                  <td style={{ padding: '12px' }}><StatusBadge status={b.status} /></td>
                  <td style={{ padding: '12px', fontWeight: 600, color: 'var(--navy)' }}>${b.price}</td>
                  <td style={{ padding: '12px' }}>
                    {b.status === 'Accepted' && (
                      <button
                        className="btn-sm"
                        style={{ background: 'var(--green)', color: 'white', border: 'none', borderRadius: 6, cursor: 'pointer', padding: '5px 12px', fontSize: 12 }}
                        onClick={() => onUpdateStatus(b.id, 'Completed')}
                      >
                        Mark Done
                      </button>
                    )}
                    {b.status === 'Pending' && (
                      <button
                        className="btn-sm"
                        style={{ background: 'var(--gray-200)', color: 'var(--gray-600)', border: 'none', borderRadius: 6, cursor: 'pointer', padding: '5px 12px', fontSize: 12 }}
                        onClick={() => onUpdateStatus(b.id, 'Cancelled')}
                      >
                        Cancel
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* ---- Providers Table ---- */}
      {tab === 'providers' && (
        <div className="grid-2">
          {providers.map(p => (
            <div key={p.id} className="card" style={{ display: 'flex', gap: 12, alignItems: 'flex-start' }}>
              <Avatar name={p.name} idx={p.avatar} />
              <div style={{ flex: 1 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                  <div style={{ fontWeight: 600, color: 'var(--navy)' }}>{p.name}</div>
                  <span className={`badge ${p.available ? 'badge-green' : 'badge-gray'}`} style={{ fontSize: 11 }}>
                    {p.available ? 'Active' : 'Offline'}
                  </span>
                </div>
                <Stars rating={p.rating} />
                <div style={{ fontSize: 12, color: 'var(--gray-500)', marginTop: 4 }}>
                  {p.reviews} reviews · {p.jobs} jobs · 📍 {p.zip}
                </div>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4, marginTop: 8 }}>
                  {p.skills.slice(0, 4).map(s => (
                    <span key={s} className="badge badge-gray" style={{ fontSize: 10 }}>{s}</span>
                  ))}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
